<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; Session::start();Auth::require(); $db=Database::getInstance();$msg='';$err='';$slb=['investigating'=>'调查中','identified'=>'已定位','monitoring'=>'监控中','resolved'=>'已解决']; if($_SERVER['REQUEST_METHOD']==='POST'){if(!Auth::validateCsrf()){$err='安全验证失败。';}else{$a=$_POST['action']??'';if($a==='add'){$si=(int)($_POST['site_id']??0);$t=trim($_POST['title']??'');$d=trim($_POST['description']??'');$sv=$_POST['severity']??'minor';$st=$_POST['status']??'investigating';if(empty($t)||$si===0){$err='站点和标题不能为空。';}else{$db->insert('incidents',['site_id'=>$si,'title'=>$t,'description'=>$d,'severity'=>$sv,'status'=>$st,'started_at'=>date('Y-m-d H:i:s')]);$msg='事件创建成功。';}}elseif($a==='update'){$id=(int)($_POST['id']??0);$st=$_POST['status']??'investigating';$uc=trim($_POST['update_content']??'');$db->update('incidents',['status'=>$st],'id=?',[$id]);if(!empty($uc))$db->insert('incident_updates',['incident_id'=>$id,'content'=>$uc,'status'=>$st]);if($st==='resolved')$db->update('incidents',['resolved_at'=>date('Y-m-d H:i:s')],'id=?',[$id]);$msg='事件更新成功。';}elseif($a==='delete'){$id=(int)($_POST['id']??0);$db->delete('incidents','id=?',[$id]);$db->delete('incident_updates','incident_id=?',[$id]);$msg='事件已删除。';}}} $incidents=$db->fetchAll("SELECT i.*,s.name as site_name FROM `incidents` i LEFT JOIN `sites` s ON i.site_id=s.id ORDER BY i.started_at DESC LIMIT 50");$sites=$db->fetchAll("SELECT id,name FROM `sites` WHERE is_active=1 ORDER BY name ASC");$u=Auth::user();?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>事件管理 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/admin.css" rel="stylesheet"></head><body><div class="admin-layout"><?php include __DIR__.'/sidebar.php';?><main class="main-content"><div class="top-bar"><h2>事件管理</h2><div class="top-bar-right"><span class="user-info"><span class="material-icons">person</span><?php echo e($u['username']);?></span></div></div><?php if($msg):?><div class="alert alert-success"><?php echo e($msg);?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?php echo e($err);?></div><?php endif;?><div class="card"><div class="card-header"><h3>创建事件</h3></div><div class="card-body"><form method="POST" class="form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="add"><div class="form-row"><div class="form-group"><label>关联站点 *</label><select name="site_id" required><option value="">-- 选择 --</option><?php foreach($sites as $st):?><option value="<?php echo $st['id'];?>"><?php echo e($st['name']);?></option><?php endforeach;?></select></div><div class="form-group"><label>严重程度</label><select name="severity"><option value="minor">轻微</option><option value="major">严重</option><option value="critical">紧急</option><option value="info">信息</option></select></div></div><div class="form-group"><label>标题 *</label><input type="text" name="title" required></div><div class="form-group"><label>描述</label><textarea name="description" rows="3"></textarea></div><button type="submit" class="btn btn-primary">创建事件</button></form></div></div><div class="card"><div class="card-header"><h3>事件列表 (<?php echo count($incidents);?>)</h3></div><div class="card-body"><?php if(empty($incidents)):?><p class="text-muted">暂无事件</p><?php else:?><?php foreach($incidents as $i):$ups=$db->fetchAll("SELECT * FROM `incident_updates` WHERE incident_id=? ORDER BY created_at ASC",[$i['id']]);?><div class="incident-item"><div class="incident-header"><div><strong><?php echo e($i['title']);?></strong> <span class="badge badge-<?php echo $i['severity'];?>"><?php echo e($i['severity']);?></span> <span class="badge badge-<?php echo $i['status'];?>"><?php echo $slb[$i['status']]??$i['status'];?></span></div><div><small><?php echo e($i['site_name']??'N/A');?> | <?php echo e($i['started_at']);?></small><?php if($i['resolved_at']):?> <small>| 解决: <?php echo e($i['resolved_at']);?></small><?php endif;?></div></div><?php if($i['description']):?><p class="incident-desc"><?php echo nl2br(e($i['description']));?></p><?php endif;?><?php if(!empty($ups)):?><div class="incident-updates"><?php foreach($ups as $up):?><div class="update-item"><span class="badge badge-<?php echo $up['status'];?>"><?php echo $slb[$up['status']]??$up['status'];?></span> <span><?php echo nl2br(e($up['content']));?></span> <small><?php echo e($up['created_at']);?></small></div><?php endforeach;?></div><?php endif;?><?php if($i['status']!=='resolved'):?><form method="POST" class="update-form"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="update"><input type="hidden" name="id" value="<?php echo $i['id'];?>"><div class="form-row"><select name="status"><?php foreach(['investigating'=>'调查中','identified'=>'已定位','monitoring'=>'监控中','resolved'=>'已解决'] as $vk=>$vl):?><option value="<?php echo $vk;?>" <?php echo $i['status']===$vk?'selected':'';?>><?php echo $vl;?></option><?php endforeach;?></select><input type="text" name="update_content" placeholder="更新说明..." style="flex:1"><button type="submit" class="btn-sm btn-primary">更新</button></div></form><?php endif;?><form method="POST" style="margin-top:8px" onsubmit="return confirm('确定删除？');"><input type="hidden" name="csrf_token" value="<?php echo e(Auth::csrfToken());?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?php echo $i['id'];?>"><button type="submit" class="btn-sm btn-danger">删除</button></form></div><?php endforeach;?><?php endif;?></div></div></main></div></body></html>